#include <stdio.h>
#include <stdbool.h>
#include <string.h>

#define MAX_ROLES 10
#define MAX_PERMISSIONS 20

typedef struct {
    char resource[50];
    char operation[20];
} Permission;

typedef struct {
    char role_name[50];
    Permission permissions[MAX_PERMISSIONS];
    int perm_count;
} Role;

typedef struct {
    char user_name[50];
    char assigned_roles[MAX_ROLES][50];
    int role_count;
} User;

bool check_permission(User *user, Role *roles, int role_count, 
                      char *resource, char *operation) {
    // Check each role assigned to user
    for (int i = 0; i < user->role_count; i++) {
        // Find the role in roles array
        for (int j = 0; j < role_count; j++) {
            if (strcmp(user->assigned_roles[i], roles[j].role_name) == 0) {
                // Check each permission in this role
                for (int k = 0; k < roles[j].perm_count; k++) {
                    if (strcmp(roles[j].permissions[k].resource, resource) == 0 &&
                        strcmp(roles[j].permissions[k].operation, operation) == 0) {
                        return true;
                    }
                }
            }
        }
    }
    return false;
}

int main() {
    Role roles[2];
    strcpy(roles[0].role_name, "Manager");
    roles[0].permissions[0] = (Permission){"documents", "read"};
    roles[0].permissions[1] = (Permission){"documents", "write"};
    roles[0].perm_count = 2;

    strcpy(roles[1].role_name, "Employee");
    roles[1].permissions[0] = (Permission){"documents", "read"};
    roles[1].perm_count = 1;

    User user;
    strcpy(user.user_name, "John");
    strcpy(user.assigned_roles[0], "Employee");
    user.role_count = 1;

    printf("Employee can read: %s\n", 
           check_permission(user, roles, 2, "documents", "read") ? "Yes" : "No");
    printf("Employee can write: %s\n", 
           check_permission(user, roles, 2, "documents", "write") ? "Yes" : "No");

    return 0;
}

import java.util.*;

class Permission {
    String resource;
    String operation;

    public Permission(String resource, String operation) {
        this.resource = resource;
        this.operation = operation;
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        Permission other = (Permission) obj;
        return resource.equals(other.resource) && operation.equals(other.operation);
    }

    @Override
    public int hashCode() {
        return Objects.hash(resource, operation);
    }
}

class Role {
    String name;
    Set<Permission> permissions;
    Role parentRole;

    public Role(String name) {
        this.name = name;
        this.permissions = new HashSet<>();
    }

    public void addPermission(Permission p) {
        permissions.add(p);
    }

    public Set<Permission> getAllPermissions() {
        Set<Permission> all = new HashSet<>(permissions);
        if (parentRole != null) {
            all.addAll(parentRole.getAllPermissions());
        }
        return all;
    }
}

class User {
    String id;
    String name;
    Set<Role> roles;

    public User(String id, String name) {
        this.id = id;
        this.name = name;
        this.roles = new HashSet<>();
    }

    public void assignRole(Role role) {
        roles.add(role);
    }

    public boolean hasPermission(String resource, String operation) {
        Permission required = new Permission(resource, operation);
        for (Role role : roles) {
            if (role.getAllPermissions().contains(required)) {
                return true;
            }
        }
        return false;
    }
}

public class DRBACSystem {
    public static void main(String[] args) {
        // Create roles with hierarchy
        Role employee = new Role("Employee");
        employee.addPermission(new Permission("files", "read"));

        Role manager = new Role("Manager");
        manager.parentRole = employee;  // Manager inherits from Employee
        manager.addPermission(new Permission("files", "write"));

        Role admin = new Role("Admin");
        admin.parentRole = manager;     // Admin inherits from Manager
        admin.addPermission(new Permission("files", "delete"));

        // Create user and assign role
        User user = new User("U1", "John Doe");
        user.assignRole(admin);  // Assign admin role

        // Test permissions
        System.out.println("Can read: " + user.hasPermission("files", "read"));   // true
        System.out.println("Can write: " + user.hasPermission("files", "write")); // true
        System.out.println("Can delete: " + user.hasPermission("files", "delete")); // true
    }
}
